mapper.select:
SELECT *
  FROM post_reaction
 WHERE user_id = #{userId}
   AND post_id = #{postId}
   AND reaction_type = #{reactionType}
 LIMIT 1

mapper.delete:
DELETE FROM post_reaction
 WHERE user_id = #{userId}
   AND post_id = #{postId}
   AND reaction_type = #{reactionType}

